size_t get_radio_index(const std::string slot_name)
{
    if (slot_name == "A") {
        return 0;
    } else if (slot_name == "B") {
        return 1;
    } else if (slot_name == "C") {
        return 2;
    } else if (slot_name == "D") {
        return 3;
    } else {
        throw uhd::key_error(str(
            boost::format("[multi_usrp]: radio slot name %s out of supported range.")
            % slot_name));
    }
}

